export enum Platform {
  SHOPEE = 'Shopee',
  LAZADA = 'Lazada',
  TIKTOK = 'TikTok',
  FACEBOOK = 'Facebook',
  WOOCOMMERCE = 'WooCommerce'
}

export type UserRole = 'owner' | 'employee' | 'collaborator';

export interface UserProfile {
  id: string;
  name: string;
  role: UserRole;
  avatar: string;
  assignedShopIds: string[];
  email?: string;
  phone?: string;
  emailVerified?: boolean;
  phoneVerified?: boolean;
}

export interface ProductVariant {
  id: string;
  name: string;
  sku: string;
  price: number;
  stock: number;
  image?: string;
}

export interface Product {
  id: string;
  name: string;
  sku: string;
  price: number;
  salePrice?: number;
  importPrice?: number;
  currency: string;
  stock: number;
  minStock?: number;
  maxStock?: number;
  warehouseStocks: Record<string, number>;
  totalSold: number;
  platforms: Platform[];
  image: string;
  gallery: string[];
  video?: string;
  description: string;
  category: string;
  status: 'active' | 'draft' | 'out_of_stock';
  weight?: number;
  length?: number;
  width?: number;
  height?: number;
  variants?: ProductVariant[];
}

export interface OrderItem {
  productId: string;
  name: string;
  image: string;
  sku: string;
  variant: string;
  quantity: number;
  price: number;
}

export interface Order {
  id: string;
  customerName: string;
  customerPhone?: string;
  address?: string;
  platform: Platform | 'Manual';
