                     <div>
                        <h3 className="font-black text-slate-800 text-xl tracking-tight">Tạo yêu cầu mới</h3>
                        <p className="text-xs text-slate-500 font-medium">Kết nối với chuyên gia thuế trong 30 giây.</p>
                     </div>
                  </div>
                  <button onClick={() => setIsNewTicketModalOpen(false)} className="p-3 hover:bg-white rounded-full text-slate-400 hover:text-red-500 transition-all"><X size={24}/></button>
               </div>

               <div className="p-8 space-y-6">
                  <div>
                     <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Chủ đề hỗ trợ</label>
                     <input 
                        type="text" 
                        value={newTicketSubject}
                        onChange={(e) => setNewTicketSubject(e.target.value)}
                        placeholder="VD: Hỗ trợ kê khai thuế quý 1/2025 Shopee..."
                        className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm font-bold text-slate-800 focus:ring-4 focus:ring-indigo-50 focus:border-indigo-300 outline-none transition-all"
                     />
                  </div>
                  <div>
                     <label className="block text-[10px] font-black text-slate-400 uppercase tracking-widest mb-2">Mô tả nội dung</label>
                     <textarea 
                        rows={5}
                        value={newTicketMessage}
                        onChange={(e) => setNewTicketMessage(e.target.value)}
                        placeholder="Nêu rõ vướng mắc của bạn: Sai doanh thu sàn, lỗi nộp tờ khai, thắc mắc mức thuế..."
                        className="w-full bg-slate-50 border border-slate-200 rounded-2xl px-6 py-4 text-sm font-medium text-slate-700 focus:ring-4 focus:ring-indigo-50 focus:border-indigo-300 outline-none transition-all resize-none"
                     />
                  </div>

                  <div className="grid grid-cols-2 gap-4">
                     <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                        <div className="flex items-center gap-3 text-indigo-600 font-bold text-xs mb-1">
                           <Clock size={16}/> 15 Phút
                        </div>
                        <div className="text-[10px] text-slate-500 font-medium">Phản hồi trung bình</div>
                     </div>
                     <div className="bg-slate-50 p-4 rounded-2xl border border-slate-100">
                        <div className="flex items-center gap-3 text-emerald-600 font-bold text-xs mb-1">
                           <ShieldCheck size={16}/> Bảo mật
                        </div>
                        <div className="text-[10px] text-slate-500 font-medium">Mã hóa dữ liệu 256-bit</div>
                     </div>
                  </div>
               </div>

               <div className="p-8 bg-slate-50 border-t border-slate-100 flex justify-end gap-3">
                  <button onClick={() => setIsNewTicketModalOpen(false)} className="px-8 py-3 text-slate-600 font-black text-xs uppercase tracking-widest hover:text-slate-800 transition-colors">Hủy bỏ</button>
                  <button onClick={handleCreateTicket} className="bg-indigo-600 text-white px-10 py-3 rounded-2xl font-black text-xs uppercase tracking-widest hover:bg-indigo-700 shadow-xl shadow-indigo-100 transition-all active:scale-95">
                     Gửi yêu cầu ngay
                  </button>
               </div>
            </div>
         </div>
      )}
    </div>
  );
};

export default TaxService;

import React, { useState, useRef, useEffect } from 'react';
import { MOCK_TAX_TICKETS } from '../services/mockData';
import { 
  // Added Image as ImageIcon to imports
  Send, Paperclip, FileText, Plus, Search, Clock, CheckCircle2, 
  MoreVertical, Headphones, X, Filter, Tag, ChevronLeft, AlertCircle, 
  ArrowRight, Download, ExternalLink, Info, User, ShieldCheck, HelpCircle,
  ChevronRight, Calendar, Archive, MessageSquare, History, Image as ImageIcon
} from 'lucide-react';
import { TaxTicket, TaxMessage } from '../types';

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

const TaxService: React.FC = () => {
  const [tickets, setTickets] = useState<TaxTicket[]>(MOCK_TAX_TICKETS);
  const [activeTicketId, setActiveTicketId] = useState<string | null>(MOCK_TAX_TICKETS[0]?.id || null);
  const [inputText, setInputText] = useState('');
  const [ticketFilter, setTicketFilter] = useState<'all' | 'open' | 'processing' | 'closed'>('all');
  const [searchTerm, setSearchTerm] = useState('');
  const [showDetailPanel, setShowDetailPanel] = useState(true);

  const messagesEndRef = useRef<HTMLDivElement>(null);

  // New Ticket Modal State
  const [isNewTicketModalOpen, setIsNewTicketModalOpen] = useState(false);
  const [newTicketSubject, setNewTicketSubject] = useState('');
  const [newTicketMessage, setNewTicketMessage] = useState('');

  const activeTicket = tickets.find(t => t.id === activeTicketId);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [activeTicket?.messages]);

  const handleSendMessage = () => {
    if (!inputText.trim() || !activeTicketId) return;

    const newMessage: TaxMessage = {
      id: `msg-${Date.now()}`,
      sender: 'user',
      content: inputText,
      type: 'text',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) + ' ' + new Date().toLocaleDateString('vi-VN')
    };

    setTickets(prev => prev.map(t => {
      if (t.id === activeTicketId) {
        return {
          ...t,
          updatedAt: new Date().toLocaleString('vi-VN'),
          messages: [...t.messages, newMessage]
        };
      }
      return t;
    }));

    setInputText('');
  };

  const handleCreateTicket = () => {
    if (!newTicketSubject || !newTicketMessage) return alert("Vui lòng nhập đầy đủ thông tin");

    const newTicket: TaxTicket = {
      id: `TK-${new Date().getFullYear()}-${Math.floor(Math.random() * 1000).toString().padStart(3, '0')}`,
      subject: newTicketSubject,
      status: 'open',
      priority: 'medium',
      tags: ['Tư vấn'],
      createdAt: new Date().toLocaleString('vi-VN'),
      updatedAt: new Date().toLocaleString('vi-VN'),
      messages: [
        {
          id: `msg-${Date.now()}`,
          sender: 'user',
          content: newTicketMessage,
          type: 'text',
          timestamp: new Date().toLocaleString('vi-VN')
        }
      ]
    };

    setTickets([newTicket, ...tickets]);
    setActiveTicketId(newTicket.id);
    setIsNewTicketModalOpen(false);
    setNewTicketSubject('');
    setNewTicketMessage('');
  };

  const filteredTickets = tickets.filter(t => {
    const matchesFilter = ticketFilter === 'all' || t.status === ticketFilter;
    const matchesSearch = t.subject.toLowerCase().includes(searchTerm.toLowerCase()) || t.id.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesFilter && matchesSearch;
  });

  const getPriorityColor = (priority: TaxTicket['priority']) => {
    switch (priority) {
      case 'high': return 'bg-red-100 text-red-700 border-red-200';
      case 'medium': return 'bg-orange-100 text-orange-700 border-orange-200';
      default: return 'bg-blue-100 text-blue-700 border-blue-200';
    }
  };

  const getStatusConfig = (status: TaxTicket['status']) => {
    switch (status) {
      case 'open': return { label: 'Mới nhận', color: 'bg-emerald-100 text-emerald-700 border-emerald-200' };
      case 'processing': return { label: 'Đang xử lý', color: 'bg-indigo-100 text-indigo-700 border-indigo-200' };
      case 'pending_action': return { label: 'Chờ khách phản hồi', color: 'bg-amber-100 text-amber-700 border-amber-200' };
      case 'closed': return { label: 'Đã đóng', color: 'bg-slate-100 text-slate-600 border-slate-200' };
      default: return { label: status, color: 'bg-slate-100' };
    }
  };

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in">
      {/* Page Title & Stats */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4 mb-6">
        <div>
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-3">
            <div className="p-2 bg-indigo-600 text-white rounded-lg shadow-lg shadow-indigo-100">
               <Headphones size={24} />
            </div>
            Dịch vụ Thuế Chuyên nghiệp
          </h2>
          <p className="text-sm text-slate-500 mt-1">Hỗ trợ tư vấn, kê khai và quyết toán thuế cho hộ kinh doanh TMĐT.</p>
        </div>
        <div className="flex items-center gap-3 w-full md:w-auto">
           <div className="hidden lg:flex items-center gap-4 mr-4 bg-white px-4 py-2 rounded-xl border border-slate-100 shadow-sm">
              <div className="text-center">
                 <div className="text-xs text-slate-400 font-bold uppercase tracking-wider">Đang mở</div>
                 <div className="text-lg font-black text-indigo-600">{tickets.filter(t => t.status !== 'closed').length}</div>
              </div>
              <div className="w-px h-8 bg-slate-100"></div>
              <div className="text-center">
                 <div className="text-xs text-slate-400 font-bold uppercase tracking-wider">Hoàn tất</div>
                 <div className="text-lg font-black text-emerald-600">{tickets.filter(t => t.status === 'closed').length}</div>
              </div>
           </div>
           <button 
             onClick={() => setIsNewTicketModalOpen(true)}
             className="flex-1 md:flex-none bg-indigo-600 text-white px-6 py-2.5 rounded-xl flex items-center justify-center gap-2 font-bold hover:bg-indigo-700 shadow-lg shadow-indigo-100 transition-all active:scale-95"
           >
             <Plus size={20} /> Tạo yêu cầu mới
           </button>
        </div>
      </div>

      <div className="flex-1 bg-white rounded-2xl shadow-xl border border-slate-100 overflow-hidden flex">

        {/* COL 1: Ticket Sidebar */}
        <div className="w-full md:w-80 border-r border-slate-100 flex flex-col bg-slate-50/50 shrink-0">
          <div className="p-4 border-b border-slate-100 space-y-3 bg-white">
             <div className="relative group">
               <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400 group-focus-within:text-indigo-500 transition-colors" size={16} />
               <input 
                 type="text" 
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 placeholder="Tìm mã hoặc tiêu đề..." 
                 className="w-full pl-10 pr-4 py-2 bg-slate-50 border border-slate-200 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500 transition-all"
               />
             </div>

             <div className="flex gap-1 overflow-x-auto no-scrollbar">
                {['all', 'open', 'processing', 'closed'].map(f => (
                   <button 
                     key={f}
                     onClick={() => setTicketFilter(f as any)}
                     className={`px-3 py-1.5 rounded-lg text-[10px] font-black uppercase tracking-wider border transition-all whitespace-nowrap ${ticketFilter === f ? 'bg-indigo-600 border-indigo-600 text-white shadow-md' : 'bg-white border-slate-200 text-slate-500 hover:border-indigo-300'}`}
                   >
                      {f === 'all' ? 'Tất cả' : f === 'open' ? 'Mới' : f === 'processing' ? 'Đang xử lý' : 'Đã đóng'}
                   </button>
                ))}
             </div>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar">
             {filteredTickets.length === 0 ? (
                <div className="flex flex-col items-center justify-center p-10 text-center opacity-40">
                   <Archive size={40} className="mb-2" />
                   <p className="text-xs font-bold">Không tìm thấy yêu cầu nào</p>
                </div>
             ) : (
                filteredTickets.map(ticket => {
                  const statusInfo = getStatusConfig(ticket.status);
                  const isSelected = activeTicketId === ticket.id;

                  return (
                    <div 
                      key={ticket.id} 
                      onClick={() => setActiveTicketId(ticket.id)}
                      className={`p-4 border-b border-slate-50 cursor-pointer transition-all relative group ${isSelected ? 'bg-white shadow-lg z-10' : 'hover:bg-white/60'}`}
                    >
                      {isSelected && <div className="absolute left-0 top-0 bottom-0 w-1 bg-indigo-600"></div>}

                      <div className="flex justify-between items-start mb-2">
                         <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded border ${getPriorityColor(ticket.priority)}`}>
                            Ưu tiên: {ticket.priority}
                         </span>
                         <span className="text-[10px] text-slate-400 font-medium">{ticket.updatedAt.split(' ')[0]}</span>
                      </div>

                      <h3 className={`text-sm font-bold line-clamp-2 leading-snug mb-2 ${isSelected ? 'text-indigo-600' : 'text-slate-800'}`}>
                         {ticket.subject}
                      </h3>

                      <div className="flex flex-wrap gap-1 mb-3">
                         {ticket.tags.slice(0, 2).map(tag => (
                            <span key={tag} className="text-[9px] bg-slate-100 text-slate-500 px-1.5 py-0.5 rounded font-bold uppercase">{tag}</span>
                         ))}
                         {ticket.tags.length > 2 && <span className="text-[9px] text-slate-400 font-bold">+{ticket.tags.length - 2}</span>}
                      </div>

                      <div className="flex justify-between items-center">
                         <span className="text-[10px] font-mono text-slate-400">{ticket.id}</span>
                         <span className={`text-[10px] px-2 py-0.5 rounded-lg font-black uppercase border ${statusInfo.color}`}>
                            {statusInfo.label}
                         </span>
                      </div>
                    </div>
                  );
                })
             )}
          </div>
        </div>

        {/* COL 2: Interaction Window */}
        <div className="flex-1 flex flex-col min-w-0 bg-slate-50/30 relative">
          {activeTicket ? (
            <>
              {/* Chat Header */}
              <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-white shadow-sm z-10 shrink-0">
                 <div className="min-w-0">
                    <h3 className="font-black text-slate-800 text-base md:text-lg flex items-center gap-3 truncate">
                       {activeTicket.subject}
                       <button onClick={() => setShowDetailPanel(!showDetailPanel)} className="p-1 hover:bg-slate-100 rounded text-slate-400">
                          <Info size={18} />
                       </button>
                    </h3>
                    <div className="flex items-center gap-3 mt-1">
                       <span className="text-xs text-slate-400 font-medium">Khởi tạo: {activeTicket.createdAt}</span>
                       <span className="w-1 h-1 bg-slate-200 rounded-full"></span>
                       <span className="text-xs font-bold text-indigo-600">ID: #{activeTicket.id}</span>
                    </div>
                 </div>
                 <div className="flex items-center gap-2">
                    <div className="hidden sm:flex items-center gap-1 bg-slate-100 px-2 py-1 rounded-lg border border-slate-200">
                       <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                       <span className="text-[10px] font-black text-slate-600 uppercase">Chuyên gia Online</span>
                    </div>
                    <button className="p-2 hover:bg-slate-100 rounded-full text-slate-400 transition-colors">
                       <MoreVertical size={20} />
                    </button>
                 </div>
              </div>

              {/* Messages Container */}
              <div className="flex-1 overflow-y-auto p-4 md:p-8 space-y-6 custom-scrollbar">
                 {/* Pagination Mock Indicator */}
                 <div className="flex justify-center mb-8">
                    <button className="text-[10px] font-black text-indigo-600 uppercase tracking-widest bg-white border border-indigo-100 px-6 py-2 rounded-full shadow-sm hover:shadow-md transition-all active:scale-95">
                       Tải thêm hội thoại cũ
                    </button>
                 </div>

                 {activeTicket.messages.map((msg, idx) => {
                    const isUser = msg.sender === 'user';
                    const isSystem = msg.sender === 'system';

                    if (isSystem) {
                       return (
                          <div key={msg.id} className="flex justify-center py-2">
                             <div className="bg-slate-200/50 backdrop-blur-sm text-slate-600 px-4 py-1.5 rounded-full text-[10px] font-black uppercase tracking-widest flex items-center gap-2 border border-slate-200 shadow-sm">
                                <AlertCircle size={12}/> {msg.content}
                             </div>
                          </div>
                       );
                    }

                    return (
                       <div key={msg.id} className={`flex ${isUser ? 'justify-end' : 'justify-start'}`}>
                          <div className={`flex flex-col max-w-[85%] md:max-w-[70%] ${isUser ? 'items-end' : 'items-start'}`}>
                             <div className={`flex items-end gap-3 ${isUser ? 'flex-row-reverse' : 'flex-row'}`}>
                                <div className={`w-8 h-8 rounded-xl flex shrink-0 items-center justify-center border shadow-sm ${isUser ? 'bg-white border-slate-200' : 'bg-indigo-600 border-indigo-600'}`}>
                                   {isUser ? (
                                      <User size={16} className="text-slate-600" />
                                   ) : (
                                      <Headphones size={16} className="text-white" />
                                   )}
                                </div>

                                <div className={`p-4 rounded-2xl text-sm leading-relaxed shadow-sm border transition-all ${
                                   isUser 
                                   ? 'bg-white text-slate-800 border-slate-100 rounded-tr-none' 
                                   : 'bg-indigo-600 text-white border-indigo-500 rounded-tl-none'
                                }`}>
                                   {msg.type === 'text' ? (
                                      <p className="whitespace-pre-wrap">{msg.content}</p>
                                   ) : (
                                      <div className={`flex items-center gap-4 p-3 rounded-xl border ${isUser ? 'bg-slate-50 border-slate-200 text-slate-800' : 'bg-white/10 border-white/20 text-white'} min-w-[220px] md:min-w-[280px]`}>
                                         <div className={`w-12 h-12 rounded-lg flex items-center justify-center shrink-0 ${isUser ? 'bg-indigo-600 text-white' : 'bg-white text-indigo-600'}`}>
                                            {msg.fileName?.endsWith('.xml') ? <div className="font-bold text-[10px]">XML</div> : <FileText size={24} />}
                                         </div>
                                         <div className="flex-1 min-w-0">
                                            <div className="font-bold text-xs truncate uppercase tracking-tight">{msg.fileName}</div>
                                            <div className="text-[10px] opacity-70 mt-1 uppercase font-bold flex items-center gap-1">
                                               File đính kèm <Download size={10} />
                                            </div>
                                         </div>
                                         <button className={`p-2 rounded-lg transition-colors ${isUser ? 'hover:bg-slate-200' : 'hover:bg-white/20'}`}>
                                            <Download size={18} />
                                         </button>
                                      </div>
                                   )}
                                </div>
                             </div>
                             <div className="flex items-center gap-2 mt-1.5 px-1">
                                <span className="text-[9px] text-slate-400 font-bold uppercase tracking-tighter">
                                   {msg.timestamp}
                                </span>
                                {isUser && <CheckCircle2 size={10} className="text-indigo-500" />}
                             </div>
                          </div>
                       </div>
                    );
                 })}
                 <div ref={messagesEndRef} />
              </div>

              {/* Interaction Bar */}
              <div className="p-4 md:p-6 bg-white border-t border-slate-100 shadow-[0_-4px_10px_-5px_rgba(0,0,0,0.05)] shrink-0">
                 <div className="flex flex-col gap-3">
                    {/* Tool Bar */}
                    <div className="flex items-center justify-between">
                       <div className="flex items-center gap-1">
                          <button className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all" title="Gửi tài liệu">
                             <Paperclip size={20} />
                          </button>
                          <button className="p-2 text-slate-400 hover:text-indigo-600 hover:bg-indigo-50 rounded-xl transition-all" title="Chụp ảnh chứng từ">
                             <ImageIcon size={20} />
                          </button>
                          <div className="w-px h-5 bg-slate-100 mx-2"></div>
                          <button className="hidden sm:flex items-center gap-2 px-3 py-1.5 bg-slate-50 hover:bg-indigo-50 text-slate-600 hover:text-indigo-600 rounded-lg text-[10px] font-bold uppercase transition-all border border-slate-200">
                             <MessageSquare size={14}/> Câu trả lời mẫu
                          </button>
                       </div>
                       <div className="flex items-center gap-2">
                          <span className="hidden md:block text-[10px] font-bold text-slate-400 uppercase tracking-widest">Đang soạn thảo...</span>
                       </div>
                    </div>

                    <div className="flex gap-3 items-end">
                       <div className="flex-1 bg-slate-50 border border-slate-200 rounded-2xl p-3 focus-within:ring-4 focus-within:ring-indigo-50 focus-within:bg-white focus-within:border-indigo-300 transition-all group">
                          <textarea 
                             rows={2}
                             value={inputText}
                             onChange={(e) => setInputText(e.target.value)}
                             onKeyDown={(e) => {
                                if (e.key === 'Enter' && !e.shiftKey) {
                                   e.preventDefault();
                                   handleSendMessage();
                                }
                             }}
                             placeholder="Đặt câu hỏi về kê khai thuế, khấu trừ hoặc nộp tiền..."
                             className="w-full bg-transparent border-none focus:ring-0 resize-none text-sm px-1 py-1 max-h-32 text-slate-800 font-medium placeholder:text-slate-400"
                          />
                       </div>
                       <button 
                          onClick={handleSendMessage}
                          disabled={!inputText.trim()}
                          className="w-14 h-14 bg-indigo-600 text-white rounded-2xl flex items-center justify-center hover:bg-indigo-700 disabled:bg-slate-200 disabled:shadow-none transition-all shadow-xl shadow-indigo-100 active:scale-95 shrink-0"
                       >
                          <Send size={24} />
                       </button>
                    </div>
                 </div>
              </div>
            </>
          ) : (
            <div className="flex-1 flex flex-col items-center justify-center text-slate-400 bg-slate-50/50 p-10 text-center">
              <div className="w-24 h-24 bg-white border border-slate-100 rounded-[2.5rem] flex items-center justify-center mb-6 shadow-xl shadow-slate-200/50">
                 <Headphones size={48} className="text-indigo-200" />
              </div>
              <h3 className="text-xl font-bold text-slate-800 mb-2">Trung tâm Hỗ trợ Thuế</h3>
              <p className="max-w-xs text-sm text-slate-500 leading-relaxed mb-8">
                 Vui lòng chọn một yêu cầu hỗ trợ hoặc tạo mới để bắt đầu tương tác với chuyên gia.
              </p>
              <button 
                onClick={() => setIsNewTicketModalOpen(true)}
                className="bg-indigo-600 text-white px-8 py-3 rounded-2xl font-bold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-100 flex items-center gap-2"
              >
                 <Plus size={20}/> Tạo yêu cầu hỗ trợ đầu tiên
              </button>
            </div>
          )}
        </div>

        {/* COL 3: Detailed Side Panel (Responsive Overlay/Sidebar) */}
        {activeTicket && showDetailPanel && (
           <div className="hidden xl:flex w-72 border-l border-slate-100 flex-col bg-white shrink-0 animate-fade-in">
              <div className="p-6 border-b border-slate-100">
                 <h4 className="font-black text-slate-800 text-xs uppercase tracking-widest mb-6">Thông tin hồ sơ</h4>

                 <div className="space-y-6">
                    <div className="flex items-center gap-3">
                       <div className="w-10 h-10 bg-indigo-50 rounded-xl flex items-center justify-center text-indigo-600">
                          <User size={20}/>
                       </div>
                       <div className="min-w-0">
                          <div className="text-[10px] text-slate-400 font-bold uppercase tracking-tighter">Hộ kinh doanh</div>
