  MessageSquare, History, Image as ImageIcon, ChevronRight, LayoutGrid
} from 'lucide-react';
import { TaxTicket, TaxMessage } from '../types';

const TaxService: React.FC = () => {
  const [tickets, setTickets] = useState<TaxTicket[]>(MOCK_TAX_TICKETS);
  const [activeTicketId, setActiveTicketId] = useState<string | null>(MOCK_TAX_TICKETS[0]?.id || null);
  const [inputText, setInputText] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  // Pagination State
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 6;

  const messagesEndRef = useRef<HTMLDivElement>(null);
  const [isNewTicketModalOpen, setIsNewTicketModalOpen] = useState(false);

  const activeTicket = tickets.find(t => t.id === activeTicketId);

  const scrollToBottom = () => {
    messagesEndRef.current?.scrollIntoView({ behavior: 'smooth' });
  };

  useEffect(() => {
    scrollToBottom();
  }, [activeTicket?.messages]);

  const handleSendMessage = () => {
    if (!inputText.trim() || !activeTicketId) return;
    const newMessage: TaxMessage = {
      id: `msg-${Date.now()}`,
      sender: 'user',
      content: inputText,
      type: 'text',
      timestamp: new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' }) + ' ' + new Date().toLocaleDateString('vi-VN')
    };
    setTickets(prev => prev.map(t => t.id === activeTicketId ? { ...t, updatedAt: 'Vừa xong', messages: [...t.messages, newMessage] } : t));
    setInputText('');
  };

  const getStatusStyle = (status: string) => {
    switch (status) {
      case 'open': return 'bg-indigo-50 text-indigo-600 border-indigo-100';
      case 'processing': return 'bg-emerald-50 text-emerald-600 border-emerald-100';
      case 'closed': return 'bg-slate-100 text-slate-500 border-slate-200';
      default: return 'bg-blue-50 text-blue-600 border-blue-100';
    }
  };

  // Pagination Logic
  const filteredTickets = tickets.filter(t => 
    t.subject.toLowerCase().includes(searchTerm.toLowerCase()) || 
    t.id.toLowerCase().includes(searchTerm.toLowerCase())
  );

  const totalPages = Math.ceil(filteredTickets.length / itemsPerPage);
  const currentTickets = filteredTickets.slice((currentPage - 1) * itemsPerPage, currentPage * itemsPerPage);

  return (
    <div className="h-[calc(100vh-6rem)] flex flex-col animate-fade-in space-y-4">
      {/* Header Section - Blue Glossy */}
      <div className="flex flex-col md:flex-row justify-between items-center bg-white p-5 rounded-[2.5rem] border border-indigo-50 shadow-xl shadow-indigo-50/50">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-gradient-to-br from-indigo-500 to-indigo-700 text-white rounded-2xl shadow-lg shadow-indigo-200 ring-4 ring-indigo-50">
            <Headphones size={24} />
          </div>
          <div>
            <h2 className="text-xl font-black text-slate-800 tracking-tight">Trung tâm Hỗ trợ Thuế</h2>
            <p className="text-xs text-slate-400 font-bold uppercase tracking-widest mt-0.5">Premium Tax Assistance</p>
          </div>
        </div>
        <div className="flex items-center gap-3 mt-4 md:mt-0">
          <div className="hidden sm:flex items-center gap-4 px-6 py-2 border-r border-slate-100">
             <div className="text-center">
                <p className="text-[10px] font-black text-slate-400 uppercase">Đang xử lý</p>
                <p className="text-lg font-black text-indigo-600">{tickets.filter(t => t.status !== 'closed').length}</p>
             </div>
             <div className="text-center">
                <p className="text-[10px] font-black text-slate-400 uppercase">Hoàn tất</p>
                <p className="text-lg font-black text-emerald-600">{tickets.filter(t => t.status === 'closed').length}</p>
             </div>
          </div>
          <button 
            onClick={() => setIsNewTicketModalOpen(true)}
            className="bg-gradient-to-r from-indigo-600 to-indigo-500 text-white px-6 py-3 rounded-2xl font-black text-xs uppercase tracking-widest shadow-xl shadow-indigo-200 hover:shadow-indigo-300 transition-all active:scale-95 flex items-center gap-2"
          >
            <Plus size={18} /> Tạo yêu cầu
          </button>
        </div>
      </div>

      {/* 3 Columns Grid */}
      <div className="flex-1 flex gap-4 overflow-hidden">

        {/* COL 1: Ticket List - Bo cong Indigo Glossy */}
        <div className="w-80 flex flex-col space-y-3 shrink-0">
          <div className="bg-white p-4 rounded-[2rem] border border-indigo-50 shadow-lg shadow-indigo-50/30">
            <div className="relative">
              <Search className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-300" size={16} />
              <input 
                type="text" 
                value={searchTerm}
                onChange={(e) => { setSearchTerm(e.target.value); setCurrentPage(1); }}
                placeholder="Tìm yêu cầu..." 
                className="w-full pl-10 pr-4 py-2.5 bg-indigo-50/30 border border-indigo-100 rounded-xl text-sm focus:outline-none focus:ring-2 focus:ring-indigo-400 transition-all font-medium"
              />
            </div>
          </div>

          <div className="flex-1 overflow-y-auto custom-scrollbar space-y-3 pr-1">
            {currentTickets.map(ticket => (
              <div 
                key={ticket.id}
                onClick={() => setActiveTicketId(ticket.id)}
                className={`p-4 rounded-[2rem] border transition-all cursor-pointer relative group overflow-hidden ${
                  activeTicketId === ticket.id 
                  ? 'bg-white border-indigo-200 shadow-xl shadow-indigo-100 translate-x-1' 
                  : 'bg-white border-slate-100 hover:border-indigo-100 hover:shadow-md'
                }`}
              >
                {activeTicketId === ticket.id && <div className="absolute left-0 top-0 bottom-0 w-1.5 bg-gradient-to-b from-indigo-500 to-indigo-700"></div>}
                <div className="flex justify-between items-start mb-2">
                  <span className={`text-[9px] font-black uppercase px-2 py-0.5 rounded-lg border ${getStatusStyle(ticket.status)}`}>
                    {ticket.status}
                  </span>
                  <span className="text-[10px] text-slate-400 font-bold">{ticket.updatedAt}</span>
                </div>
                <h4 className={`text-sm font-black leading-tight mb-2 ${activeTicketId === ticket.id ? 'text-indigo-700' : 'text-slate-700'}`}>
                  {ticket.subject}
                </h4>
                <div className="flex items-center gap-2">
                  <div className="w-5 h-5 rounded-full bg-slate-100 flex items-center justify-center text-[10px] font-black text-slate-500">#</div>
                  <span className="text-[10px] font-mono text-slate-400">{ticket.id}</span>
                </div>
              </div>
            ))}
          </div>

          {/* Pagination Controls */}
          {totalPages > 1 && (
            <div className="bg-white p-3 rounded-[1.5rem] border border-indigo-50 flex items-center justify-between shadow-sm">
                <button 
                  disabled={currentPage === 1}
                  onClick={() => setCurrentPage(p => Math.max(1, p - 1))}
                  className="p-1.5 rounded-lg hover:bg-indigo-50 text-indigo-600 disabled:opacity-30 transition-colors"
                >
                    <ChevronLeft size={18} />
                </button>
                <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Trang {currentPage} / {totalPages}</span>
                <button 
                  disabled={currentPage === totalPages}
                  onClick={() => setCurrentPage(p => Math.min(totalPages, p + 1))}
                  className="p-1.5 rounded-lg hover:bg-indigo-50 text-indigo-600 disabled:opacity-30 transition-colors"
                >
                    <ChevronRight size={18} />
                </button>
            </div>
          )}
        </div>

        {/* COL 2: Interaction Window - Glossy Blue Bubble Style */}
        <div className="flex-1 bg-white rounded-[3rem] border border-indigo-50 shadow-2xl shadow-indigo-100/50 flex flex-col overflow-hidden relative">
          {activeTicket ? (
            <>
              {/* Chat Header */}
              <div className="p-6 border-b border-indigo-50 flex justify-between items-center bg-gradient-to-r from-white to-indigo-50/30">
                <div className="flex items-center gap-4">
                  <div className="w-12 h-12 bg-indigo-600 rounded-2xl flex items-center justify-center text-white shadow-lg shadow-indigo-200">
                    <User size={24} />
                  </div>
                  <div>
                    <h3 className="font-black text-slate-800 text-lg leading-none">{activeTicket.subject}</h3>
                    <div className="flex items-center gap-2 mt-1.5">
                      <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                      <span className="text-[10px] font-black text-slate-400 uppercase tracking-widest">Chuyên gia đang trực tuyến</span>
                    </div>
                  </div>
                </div>
                <button className="p-3 hover:bg-indigo-100 text-indigo-400 hover:text-indigo-600 rounded-full transition-all">
                  <MoreVertical size={20} />
                </button>
              </div>

              {/* Chat Content */}
              <div className="flex-1 overflow-y-auto p-8 space-y-6 custom-scrollbar bg-[radial-gradient(#e0e7ff_0.5px,transparent_0.5px)] [background-size:20px_20px]">
                {activeTicket.messages.map((msg) => {
                  const isUser = msg.sender === 'user';
                  const isSystem = msg.sender === 'system';
                  if (isSystem) return (
                    <div key={msg.id} className="flex justify-center">
                      <span className="bg-slate-100/80 backdrop-blur-sm text-[10px] font-black uppercase text-slate-400 px-4 py-1.5 rounded-full border border-slate-200 tracking-tighter">
                        {msg.content}
                      </span>
                    </div>
                  );
                  return (
                    <div key={msg.id} className={`flex ${isUser ? 'justify-end' : 'justify-start'}`}>
                      <div className={`flex flex-col max-w-[80%] ${isUser ? 'items-end' : 'items-start'}`}>
                        <div className={`p-4 rounded-[2rem] text-sm leading-relaxed shadow-sm border transition-all ${
                          isUser 
                          ? 'bg-gradient-to-br from-indigo-500 to-indigo-600 text-white border-indigo-400 rounded-tr-none' 
                          : 'bg-white text-slate-700 border-indigo-50 rounded-tl-none shadow-indigo-50'
                        }`}>
