                     <div className={`px-4 py-2 rounded-lg border flex items-center bg-white ${getPlatformStyle(integration.platform)}`}>
                        {logoUrl ? (
                          <img src={logoUrl} alt={integration.platform} className="h-6 w-auto object-contain" />
