import React, { useState } from 'react';
import { ExternalProduct, ProductSyncLog, Platform } from '../types';
import { MOCK_EXTERNAL_PRODUCTS, MOCK_PRODUCT_SYNC_HISTORY, INITIAL_INTEGRATIONS } from '../services/mockData';
import { 
  RefreshCw, Filter, Search, Link as LinkIcon, History, 
  CheckCircle2, XCircle, AlertTriangle, ArrowRight, X, Loader2, Store, ChevronDown, Wrench, Settings, Globe
} from 'lucide-react';

const LOGOS: Record<string, string> = {
  [Platform.SHOPEE]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/f/fe/Shopee.svg/2560px-Shopee.svg.png',
  [Platform.LAZADA]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/4/4d/Lazada_%282019%29.svg/1200px-Lazada_%282019%29.svg.png',
  [Platform.TIKTOK]: 'https://upload.wikimedia.org/wikipedia/en/thumb/a/a9/TikTok_logo.svg/2560px-TikTok_logo.svg.png',
  [Platform.FACEBOOK]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/b/b8/2021_Facebook_icon.svg/2048px-2021_Facebook_icon.svg.png',
  [Platform.WOOCOMMERCE]: 'https://upload.wikimedia.org/wikipedia/commons/thumb/2/2a/WooCommerce_logo.svg/1200px-WooCommerce_logo.svg.png',
};

const formatCurrency = (value: number) => {
  return new Intl.NumberFormat('vi-VN', { style: 'currency', currency: 'VND' }).format(value);
};

const EcommerceProducts: React.FC = () => {
  const [products, setProducts] = useState<ExternalProduct[]>(MOCK_EXTERNAL_PRODUCTS);
  const [syncHistory, setSyncHistory] = useState<ProductSyncLog[]>(MOCK_PRODUCT_SYNC_HISTORY);

  // UI State
  const [searchTerm, setSearchTerm] = useState('');
  const [filterPlatform, setFilterPlatform] = useState<string>('all');
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [showHistoryModal, setShowHistoryModal] = useState(false);
  const [isSyncing, setIsSyncing] = useState<string | null>(null); // 'all' or product ID
  const [bulkSyncShopId, setBulkSyncShopId] = useState<string>('');

  // Error Fix Modal State
  const [fixProduct, setFixProduct] = useState<ExternalProduct | null>(null);
  const [isFixing, setIsFixing] = useState(false);

  const filteredProducts = products.filter(p => {
    const matchSearch = p.name.toLowerCase().includes(searchTerm.toLowerCase()) || p.sku.toLowerCase().includes(searchTerm.toLowerCase());
    const matchPlatform = filterPlatform === 'all' || p.platform === filterPlatform;
    const matchStatus = filterStatus === 'all' || p.syncStatus === filterStatus;
    return matchSearch && matchPlatform && matchStatus;
  });

  const stats = {
    total: products.length,
    synced: products.filter(p => p.syncStatus === 'synced').length,
    unsynced: products.filter(p => p.syncStatus === 'unsynced').length,
    error: products.filter(p => p.syncStatus === 'error').length
  };

  const handleSync = (productId: string) => {
    setIsSyncing(productId);
    setTimeout(() => {
      setProducts(prev => prev.map(p => {
        if (p.id === productId) {
          return {
            ...p,
            syncStatus: 'synced',
            lastSyncAt: new Date().toLocaleString('vi-VN'),
            errorMsg: undefined
          };
        }
        return p;
      }));
      setIsSyncing(null);
    }, 1500);
  };

  const handleBulkSync = () => {
    if (!bulkSyncShopId) return alert("Vui lòng chọn gian hàng để đồng bộ.");

    setIsSyncing('all');
    // Simulate bulk sync with a delay
    setTimeout(() => {
      // Mock log entry
      const newLog: ProductSyncLog = {
        id: `log-${Date.now()}`,
        shopId: bulkSyncShopId,
        shopName: INITIAL_INTEGRATIONS.find(i => i.shops.some(s => s.id === bulkSyncShopId))?.shops.find(s => s.id === bulkSyncShopId)?.name || 'Unknown',
        platform: Platform.SHOPEE, // Mock platform
        totalItems: 50,
        syncedItems: 45,
        failedItems: 5,
        status: 'partial',
        performedBy: 'Admin',
        timestamp: new Date().toLocaleString('vi-VN')
      };

      setSyncHistory([newLog, ...syncHistory]);
      setIsSyncing(null);
      alert("Đồng bộ hoàn tất! Kiểm tra lịch sử để xem chi tiết.");
    }, 2500);
  };

  const handleFixError = (action: 'link' | 'create' | 'ignore') => {
    if (!fixProduct) return;
    setIsFixing(true);

    setTimeout(() => {
        setIsFixing(false);
        setProducts(prev => prev.map(p => {
            if (p.id === fixProduct.id) {
                if (action === 'link' || action === 'create') {
                    return {
                        ...p,
                        syncStatus: 'synced',
                        errorMsg: undefined,
                        lastSyncAt: 'Vừa xong'
                    };
                }
            }
            return p;
        }));
        setFixProduct(null);
    }, 1000);
  };

  return (
    <div className="space-y-6 animate-fade-in pb-10 h-full flex flex-col">
      {/* Header with Enhanced Sync Action */}
      <div className="flex flex-col lg:flex-row justify-between items-start lg:items-center gap-6 shrink-0 bg-white p-6 rounded-2xl shadow-sm border border-slate-100 relative overflow-hidden">
        {/* Decorative background blur */}
        <div className="absolute top-0 right-0 w-64 h-64 bg-indigo-50 rounded-full blur-3xl -mr-16 -mt-16 pointer-events-none"></div>

        <div className="relative z-10">
          <h2 className="text-2xl font-bold text-slate-800 flex items-center gap-2">
            Sản phẩm TMĐT 
            <span className="text-xs font-normal text-indigo-600 bg-indigo-50 px-3 py-1 rounded-full border border-indigo-100 flex items-center gap-1">
                <Globe size={12} /> Quản lý tập trung
            </span>
          </h2>
          <p className="text-sm text-slate-500 mt-1 max-w-md">
            Đồng bộ và quản lý trạng thái sản phẩm từ tất cả các gian hàng Shopee, Lazada, TikTok Shop... tại một nơi duy nhất.
          </p>
        </div>

        <div className="flex flex-col sm:flex-row gap-3 w-full lg:w-auto items-stretch sm:items-center relative z-10">
           <button 
            onClick={() => setShowHistoryModal(true)}
            className="flex items-center justify-center gap-2 px-4 py-3 bg-white border border-slate-200 text-slate-600 rounded-xl text-sm font-bold hover:bg-slate-50 hover:text-indigo-600 transition-colors shadow-sm"
          >
            <History size={18} /> 
            <span className="hidden sm:inline">Lịch sử đồng bộ</span>
          </button>

          <div className="p-1.5 bg-gradient-to-r from-blue-600 to-indigo-600 rounded-xl shadow-lg shadow-indigo-200/50 flex items-center gap-2 pl-2 pr-1.5 flex-1 sm:flex-none transition-all hover:shadow-indigo-300 hover:scale-[1.01]">
             <div className="relative flex-1 sm:flex-none sm:w-64">
               <Store className="absolute left-3 top-1/2 -translate-y-1/2 text-indigo-100" size={18} />
               <select 
                 value={bulkSyncShopId}
                 onChange={(e) => setBulkSyncShopId(e.target.value)}
                 className="w-full bg-white/10 text-white text-sm font-bold border-none focus:ring-0 cursor-pointer py-2.5 pl-10 pr-8 rounded-lg outline-none placeholder-white/70 appearance-none hover:bg-white/20 transition-colors"
               >
                 <option value="" className="text-slate-800">Chọn gian hàng cần đồng bộ...</option>
                 {INITIAL_INTEGRATIONS.flatMap(i => i.shops).map(shop => (
                   <option key={shop.id} value={shop.id} className="text-slate-800">{shop.name}</option>
                 ))}
               </select>
               <ChevronDown className="absolute right-3 top-1/2 -translate-y-1/2 text-indigo-200 pointer-events-none" size={16} />
             </div>
             <button 
               onClick={handleBulkSync}
               disabled={isSyncing === 'all' || !bulkSyncShopId}
               className="whitespace-nowrap px-6 py-2.5 bg-white text-indigo-700 rounded-lg text-sm font-extrabold hover:bg-indigo-50 transition-all disabled:opacity-50 disabled:cursor-not-allowed flex items-center gap-2 shadow-sm"
             >
               {isSyncing === 'all' ? <Loader2 size={18} className="animate-spin text-indigo-600"/> : <RefreshCw size={18} strokeWidth={2.5} />}
               Đồng bộ ngay
             </button>
          </div>
        </div>
      </div>

      {/* Interactive Stats Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 shrink-0">
         <div 
            onClick={() => setFilterStatus('all')}
            className={`p-4 rounded-xl border shadow-sm flex items-center gap-3 cursor-pointer transition-all duration-200 transform hover:-translate-y-1 ${
               filterStatus === 'all' 
               ? 'bg-indigo-50 border-indigo-500 ring-2 ring-indigo-500/20' 
               : 'bg-white border-slate-100 hover:border-indigo-300 hover:shadow-md'
            }`}
         >
            <div className={`p-2.5 rounded-lg transition-colors ${filterStatus === 'all' ? 'bg-indigo-200 text-indigo-700' : 'bg-slate-100 text-slate-500'}`}>
               <Filter size={20}/>
            </div>
            <div>
               <div className={`text-sm font-medium ${filterStatus === 'all' ? 'text-indigo-700' : 'text-slate-500'}`}>Tổng sản phẩm</div>
               <div className="text-2xl font-bold text-slate-800 leading-none mt-1">{stats.total}</div>
            </div>
         </div>

         <div 
            onClick={() => setFilterStatus('synced')}
            className={`p-4 rounded-xl border shadow-sm flex items-center gap-3 cursor-pointer transition-all duration-200 transform hover:-translate-y-1 ${
               filterStatus === 'synced' 
               ? 'bg-green-50 border-green-500 ring-2 ring-green-500/20' 
               : 'bg-white border-slate-100 hover:border-green-300 hover:shadow-md'
            }`}
         >
            <div className={`p-2.5 rounded-lg transition-colors ${filterStatus === 'synced' ? 'bg-green-200 text-green-700' : 'bg-green-50 text-green-600'}`}>
               <CheckCircle2 size={20}/>
            </div>
            <div>
               <div className={`text-sm font-medium ${filterStatus === 'synced' ? 'text-green-700' : 'text-slate-500'}`}>Đã liên kết</div>
               <div className="text-2xl font-bold text-slate-800 leading-none mt-1">{stats.synced}</div>
            </div>
         </div>

         <div 
            onClick={() => setFilterStatus('unsynced')}
            className={`p-4 rounded-xl border shadow-sm flex items-center gap-3 cursor-pointer transition-all duration-200 transform hover:-translate-y-1 ${
               filterStatus === 'unsynced' 
               ? 'bg-orange-50 border-orange-500 ring-2 ring-orange-500/20' 
               : 'bg-white border-slate-100 hover:border-orange-300 hover:shadow-md'
            }`}
         >
            <div className={`p-2.5 rounded-lg transition-colors ${filterStatus === 'unsynced' ? 'bg-orange-200 text-orange-700' : 'bg-orange-50 text-orange-600'}`}>
               <LinkIcon size={20}/>
            </div>
            <div>
               <div className={`text-sm font-medium ${filterStatus === 'unsynced' ? 'text-orange-700' : 'text-slate-500'}`}>Chưa liên kết</div>
               <div className="text-2xl font-bold text-slate-800 leading-none mt-1">{stats.unsynced}</div>
            </div>
         </div>

         <div 
            onClick={() => setFilterStatus('error')}
            className={`p-4 rounded-xl border shadow-sm flex items-center gap-3 cursor-pointer transition-all duration-200 transform hover:-translate-y-1 ${
               filterStatus === 'error' 
               ? 'bg-red-50 border-red-500 ring-2 ring-red-500/20' 
               : 'bg-white border-slate-100 hover:border-red-300 hover:shadow-md'
            }`}
         >
            <div className={`p-2.5 rounded-lg transition-colors ${filterStatus === 'error' ? 'bg-red-200 text-red-700' : 'bg-red-50 text-red-600'}`}>
               <AlertTriangle size={20}/>
            </div>
            <div>
               <div className={`text-sm font-medium ${filterStatus === 'error' ? 'text-red-700' : 'text-slate-500'}`}>Lỗi đồng bộ</div>
               <div className="text-2xl font-bold text-slate-800 leading-none mt-1">{stats.error}</div>
            </div>
         </div>
      </div>

      {/* Filters & List */}
      <div className="bg-white rounded-xl shadow-sm border border-slate-100 flex flex-col flex-1 overflow-hidden">
         <div className="p-4 border-b border-slate-100 flex flex-wrap gap-4 items-center bg-slate-50/50">
            <div className="relative flex-1 min-w-[200px]">
               <input 
                 type="text" 
                 placeholder="Tìm theo tên sản phẩm, SKU sàn..." 
                 value={searchTerm}
                 onChange={(e) => setSearchTerm(e.target.value)}
                 className="w-full pl-9 pr-4 py-2 bg-white border border-slate-200 rounded-lg text-sm focus:outline-none focus:ring-2 focus:ring-indigo-500"
               />
               <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
            </div>

            <select 
              value={filterPlatform}
              onChange={(e) => setFilterPlatform(e.target.value)}
              className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 focus:border-indigo-500"
            >
               <option value="all">Tất cả sàn</option>
               {Object.values(Platform).map(p => <option key={p} value={p}>{p}</option>)}
            </select>

            <select 
              value={filterStatus}
              onChange={(e) => setFilterStatus(e.target.value)}
              className="bg-white border border-slate-200 rounded-lg px-3 py-2 text-sm focus:ring-indigo-500 focus:border-indigo-500"
            >
               <option value="all">Tất cả trạng thái</option>
               <option value="synced">Đã đồng bộ</option>
               <option value="unsynced">Chưa liên kết</option>
               <option value="error">Lỗi</option>
            </select>
         </div>

         <div className="flex-1 overflow-auto">
            <table className="w-full text-sm text-left">
               <thead className="bg-slate-50 text-slate-500 font-semibold border-b border-slate-100 sticky top-0 z-10 shadow-sm">
                  <tr>
                     <th className="px-6 py-4 w-12 text-center">#</th>
                     <th className="px-6 py-4">Sản phẩm (Trên sàn)</th>
                     <th className="px-6 py-4">Gian hàng</th>
                     <th className="px-6 py-4 text-right">Giá bán</th>
                     <th className="px-6 py-4 text-center">Tồn kho</th>
                     <th className="px-6 py-4">Trạng thái</th>
                     <th className="px-6 py-4">Lần cuối</th>
                     <th className="px-6 py-4 text-right">Hành động</th>
                  </tr>
               </thead>
               <tbody className="divide-y divide-slate-100">
                  {filteredProducts.length === 0 ? (
                     <tr><td colSpan={8} className="text-center py-12 text-slate-400">Không tìm thấy sản phẩm phù hợp</td></tr>
                  ) : (
                     filteredProducts.map((p, idx) => (
                        <tr key={p.id} className="hover:bg-slate-50 group">
                           <td className="px-6 py-4 text-center text-slate-400">{idx + 1}</td>
                           <td className="px-6 py-4">
                              <div className="flex items-center gap-3">
                                 <img src={p.image} className="w-10 h-10 rounded-lg object-cover border border-slate-200 bg-white" />
                                 <div className="min-w-0 max-w-xs">
                                    <div className="font-medium text-slate-800 line-clamp-1" title={p.name}>{p.name}</div>
                                    <div className="text-xs text-slate-500 flex items-center gap-2">
                                       <span className="bg-slate-100 px-1.5 rounded font-mono">ID: {p.externalId}</span>
                                       <span>SKU: {p.sku}</span>
                                    </div>
                                 </div>
                              </div>
                           </td>
                           <td className="px-6 py-4">
                              <div className="flex items-center gap-2">
                                 <div className="w-6 h-6 rounded border border-slate-200 flex items-center justify-center p-0.5 bg-white">
                                    {LOGOS[p.platform] && <img src={LOGOS[p.platform]} className="w-full h-full object-contain"/>}
                                 </div>
                                 <div className="truncate max-w-[120px] text-xs font-medium text-slate-700" title={p.shopName}>{p.shopName}</div>
                              </div>
                           </td>
                           <td className="px-6 py-4 text-right font-medium text-slate-700">{formatCurrency(p.price)}</td>
                           <td className="px-6 py-4 text-center">{p.stock}</td>
                           <td className="px-6 py-4">
                              {p.syncStatus === 'synced' && <span className="bg-green-100 text-green-700 px-2 py-1 rounded text-xs font-bold flex items-center gap-1 w-fit border border-green-200"><CheckCircle2 size={12}/> Đã liên kết</span>}
                              {p.syncStatus === 'unsynced' && <span className="bg-orange-100 text-orange-700 px-2 py-1 rounded text-xs font-bold flex items-center gap-1 w-fit border border-orange-200"><LinkIcon size={12}/> Chưa liên kết</span>}
                              {p.syncStatus === 'error' && (
                                 <div className="flex flex-col">
                                    <span className="bg-red-100 text-red-700 px-2 py-1 rounded text-xs font-bold flex items-center gap-1 w-fit border border-red-200"><XCircle size={12}/> Lỗi</span>
                                    <span className="text-[10px] text-red-500 mt-0.5 max-w-[150px] truncate" title={p.errorMsg}>{p.errorMsg}</span>
                                 </div>
                              )}
                           </td>
                           <td className="px-6 py-4 text-xs text-slate-500">{p.lastSyncAt}</td>
                           <td className="px-6 py-4 text-right">
                              {p.syncStatus === 'error' ? (
                                <button 
                                    onClick={() => setFixProduct(p)}
                                    className="bg-red-50 text-red-600 px-3 py-1.5 rounded-lg text-xs font-bold border border-red-100 hover:bg-red-100 transition-colors flex items-center gap-1 ml-auto"
                                >
                                    <Wrench size={12} /> Khắc phục
                                </button>
                              ) : (
                                <button 
                                    onClick={() => handleSync(p.id)}
                                    disabled={isSyncing === p.id}
                                    className="text-indigo-600 hover:text-indigo-800 p-2 hover:bg-indigo-50 rounded-lg transition-colors disabled:opacity-50"
                                    title="Đồng bộ lại"
                                >
                                    {isSyncing === p.id ? <Loader2 size={16} className="animate-spin"/> : <RefreshCw size={16} />}
                                </button>
                              )}
                           </td>
                        </tr>
                     ))
                  )}
               </tbody>
            </table>
         </div>
      </div>

      {/* Sync History Modal */}
      {showHistoryModal && (
         <div className="fixed inset-0 bg-black/50 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-3xl overflow-hidden flex flex-col max-h-[80vh]">
               <div className="p-4 border-b border-slate-100 flex justify-between items-center bg-slate-50">
                  <h3 className="font-bold text-lg text-slate-800 flex items-center gap-2">
                     <History size={20} className="text-indigo-600"/> Lịch sử đồng bộ sản phẩm
                  </h3>
                  <button onClick={() => setShowHistoryModal(false)} className="text-slate-400 hover:text-slate-600"><X size={20}/></button>
               </div>
               <div className="flex-1 overflow-auto p-0">
                  <table className="w-full text-sm text-left">
                     <thead className="bg-white text-slate-500 font-semibold border-b border-slate-100 sticky top-0 z-10">
                        <tr>
                           <th className="px-6 py-3">Thời gian</th>
                           <th className="px-6 py-3">Gian hàng</th>
                           <th className="px-6 py-3 text-center">Tổng SP</th>
                           <th className="px-6 py-3 text-center">Thành công</th>
                           <th className="px-6 py-3 text-center">Thất bại</th>
                           <th className="px-6 py-3 text-center">Trạng thái</th>
                           <th className="px-6 py-3">Người thực hiện</th>
                        </tr>
                     </thead>
                     <tbody className="divide-y divide-slate-100">
                        {syncHistory.map(log => (
                           <tr key={log.id} className="hover:bg-slate-50">
                              <td className="px-6 py-3 text-slate-600">{log.timestamp}</td>
                              <td className="px-6 py-3">
                                 <div className="font-medium text-slate-800">{log.shopName}</div>
                                 <div className="text-xs text-slate-500">{log.platform}</div>
                              </td>
                              <td className="px-6 py-3 text-center">{log.totalItems}</td>
                              <td className="px-6 py-3 text-center text-green-600 font-bold">{log.syncedItems}</td>
                              <td className="px-6 py-3 text-center text-red-600 font-bold">{log.failedItems}</td>
                              <td className="px-6 py-3 text-center">
                                 <span className={`px-2 py-1 rounded text-[10px] font-bold uppercase ${
                                    log.status === 'success' ? 'bg-green-100 text-green-700' : 
                                    log.status === 'failed' ? 'bg-red-100 text-red-700' : 'bg-orange-100 text-orange-700'
                                 }`}>
                                    {log.status}
                                 </span>
                              </td>
                              <td className="px-6 py-3 text-slate-500 text-xs">{log.performedBy}</td>
                           </tr>
                        ))}
                     </tbody>
                  </table>
               </div>
               <div className="p-4 border-t border-slate-100 bg-slate-50 flex justify-end">
                  <button onClick={() => setShowHistoryModal(false)} className="px-4 py-2 bg-white border border-slate-200 text-slate-600 rounded-lg text-sm font-medium hover:bg-slate-100">Đóng</button>
               </div>
            </div>
         </div>
      )}

      {/* Fix Error Modal */}
      {fixProduct && (
        <div className="fixed inset-0 bg-black/60 z-50 flex items-center justify-center p-4 backdrop-blur-sm animate-fade-in">
            <div className="bg-white rounded-xl shadow-2xl w-full max-w-md overflow-hidden">
                <div className="p-4 border-b border-red-100 bg-red-50 flex justify-between items-center">
                    <h3 className="font-bold text-lg text-red-800 flex items-center gap-2">
                        <AlertTriangle size={20} className="text-red-600"/> Xử lý lỗi đồng bộ
                    </h3>
                    <button onClick={() => setFixProduct(null)} className="text-red-400 hover:text-red-600"><X size={20}/></button>
                </div>
                <div className="p-6">
                    <div className="flex gap-3 mb-6 p-3 bg-slate-50 rounded-lg border border-slate-100">
                        <img src={fixProduct.image} className="w-12 h-12 rounded object-cover border border-slate-200" />
                        <div>
                            <div className="font-bold text-sm text-slate-800 line-clamp-1">{fixProduct.name}</div>
                            <div className="text-xs text-slate-500 font-mono">SKU: {fixProduct.sku}</div>
                        </div>
                    </div>

                    <div className="text-sm font-medium text-slate-700 mb-2">Nguyên nhân lỗi:</div>
                    <div className="p-3 bg-red-50 text-red-700 text-sm rounded-lg border border-red-100 mb-6">
                        {fixProduct.errorMsg}
                    </div>

                    <div className="space-y-3">
                        <button 
                            onClick={() => handleFixError('link')}
                            disabled={isFixing}
                            className="w-full p-3 border border-slate-200 rounded-xl text-left hover:bg-indigo-50 hover:border-indigo-200 transition-all group flex items-center justify-between"
                        >
                            <div>
                                <div className="font-bold text-slate-800 group-hover:text-indigo-700 text-sm">Liên kết thủ công</div>
                                <div className="text-xs text-slate-500">Chọn sản phẩm tương ứng trong kho để map lại</div>
                            </div>
                            <ChevronDown className="-rotate-90 text-slate-300 group-hover:text-indigo-400" size={16}/>
                        </button>
                        <button 
                            onClick={() => handleFixError('create')}
                            disabled={isFixing}
                            className="w-full p-3 border border-slate-200 rounded-xl text-left hover:bg-green-50 hover:border-green-200 transition-all group flex items-center justify-between"
                        >
                            <div>
                                <div className="font-bold text-slate-800 group-hover:text-green-700 text-sm">Tạo mới trên hệ thống</div>
                                <div className="text-xs text-slate-500">Tạo sản phẩm mới trong kho từ dữ liệu sàn</div>
                            </div>
                            <ChevronDown className="-rotate-90 text-slate-300 group-hover:text-green-400" size={16}/>
                        </button>
                        <button 
                            onClick={() => setFixProduct(null)}
                            disabled={isFixing}
                            className="w-full p-3 border border-slate-200 rounded-xl text-left hover:bg-slate-50 transition-all group flex items-center justify-between"
                        >
                            <div>
                                <div className="font-bold text-slate-800 text-sm">Bỏ qua lỗi này</div>
                                <div className="text-xs text-slate-500">Không hiển thị cảnh báo nữa</div>
                            </div>
                            <X size={16} className="text-slate-300"/>
                        </button>
                    </div>
                </div>
                {isFixing && (
                    <div className="absolute inset-0 bg-white/80 flex items-center justify-center flex-col gap-2">
                        <Loader2 size={32} className="animate-spin text-indigo-600"/>
                        <span className="text-sm font-bold text-indigo-900">Đang xử lý...</span>
                    </div>
                )}
            </div>
        </div>
      )}
    </div>
  );
};

export default EcommerceProducts;

import React, { useState } from 'react';
import { LayoutDashboard, ShoppingBag, Package, Settings, LogOut, MessageSquareText, PieChart, Megaphone, Archive, FileSpreadsheet, Headphones, Wrench, Crown, Sparkles, X, PlusCircle, BookText, BookOpen, MessageSquarePlus, Newspaper, Globe } from 'lucide-react';

interface SidebarProps {
  activeTab: string;
  setActiveTab: (tab: string) => void;
  onLogout: () => void;
  isOpen: boolean;
  onClose: () => void;
  onOpenGuide: () => void;
  onOpenFeedback: () => void;
}

const Sidebar: React.FC<SidebarProps> = ({ activeTab, setActiveTab, onLogout, isOpen, onClose }) => {
  const [hoveredItem, setHoveredItem] = useState<string | null>(null);

  const mainMenuItems = [
    { id: 'dashboard', label: 'Tổng quan', icon: LayoutDashboard },
    { id: 'reports', label: 'Báo cáo', icon: PieChart },
    { id: 'create-order', label: 'Tạo Đơn ngoài sàn', icon: PlusCircle },
    { id: 'orders', label: 'Đơn hàng', icon: Package, color: 'orange' },
    { id: 'products', label: 'Sản phẩm', icon: ShoppingBag },
    { id: 'ecommerce-products', label: 'Sản phẩm TMĐT', icon: Globe },
    { id: 'inventory', label: 'Kho hàng', icon: Archive },
    { id: 'marketing', label: 'Marketing', icon: Megaphone },
    { id: 'messages', label: 'Tin nhắn', icon: MessageSquareText, color: 'yellow' },
    { id: 'invoices', label: 'Sổ & Hóa Đơn', icon: BookText },
    { id: 'tax', label: 'Báo cáo Thuế', icon: FileSpreadsheet }, 
    { id: 'tax-service', label: 'Dịch vụ Thuế', icon: Headphones, color: 'green' },
    { id: 'tools', label: 'Công cụ', icon: Wrench },
    { id: 'integrations', label: 'Cấu hình', icon: Settings },
  ];

  const supportMenuItems = [
    { id: 'news', label: 'Tin tức', icon: Newspaper, featured: true },
    { id: 'guide', label: 'Hướng dẫn sử dụng', icon: BookOpen },
    { id: 'feedback', label: 'Góp ý tính năng', icon: MessageSquarePlus },
  ];

  const handleItemClick = (id: string) => {
    setActiveTab(id);
    onClose(); 
  };

  const getCustomStyles = (id: string, isActive: boolean) => {
    if (isActive) return 'bg-indigo-50 text-indigo-700 shadow-sm ring-1 ring-indigo-100 font-bold';
    return 'text-slate-600 hover:text-indigo-600 font-medium transition-colors'; 
  };

  const getIconColor = (id: string, isActive: boolean) => {
    if (isActive) return 'text-indigo-600';
    switch (id) {
      case 'orders': return 'text-orange-500 group-hover:text-orange-600';
      case 'messages': return 'text-amber-500 group-hover:text-amber-600';
      case 'tax-service': return 'text-emerald-500 group-hover:text-emerald-600';
      default: return 'text-slate-400 group-hover:text-slate-600';
    }
  };

  const renderMenuItem = (item: any) => {
    const Icon = item.icon;
    const isActive = activeTab === item.id;

    return (
      <div key={item.id} className="relative group">
        <button
          onClick={() => handleItemClick(item.id)}
          className={`w-full flex items-center gap-3 px-3 py-2.5 rounded-lg text-sm transition-all duration-200 ${getCustomStyles(item.id, isActive)}`}
        >
          <Icon size={18} className={`transition-colors ${getIconColor(item.id, isActive)}`} />
          <span className={isActive ? '' : ''}>{item.label}</span>
          {item.featured && !isActive && <Sparkles size={12} className="ml-auto text-indigo-400 animate-pulse" />}
        </button>
      </div>
    );
  };

  return (
    <>
      {/* Mobile Overlay */}
      {isOpen && (
        <div 
          className="fixed inset-0 bg-slate-900/50 z-40 lg:hidden backdrop-blur-sm transition-opacity"
          onClick={onClose}
        />
      )}

      {/* Sidebar Container */}
      <aside className={`
        fixed lg:static inset-y-0 left-0 z-50 w-64 bg-white border-r border-slate-200 
        flex flex-col h-screen shadow-xl lg:shadow-none transition-transform duration-300 ease-in-out
        ${isOpen ? 'translate-x-0' : '-translate-x-full lg:translate-x-0'}
      `}>
        {/* Brand Header */}
        <div className="h-16 flex items-center px-6 border-b border-slate-100 shrink-0">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 bg-indigo-600 rounded-lg flex items-center justify-center text-white font-bold shadow-md shadow-indigo-200">
              <span className="text-lg">O</span>
            </div>
            <h1 className="text-lg font-bold text-slate-800 tracking-tight">OmniSales</h1>
          </div>
          <button onClick={onClose} className="lg:hidden ml-auto text-slate-400 hover:text-slate-600">
            <X size={20} />
          </button>
        </div>

        {/* Navigation */}
        <nav className="flex-1 flex flex-col overflow-hidden py-4 px-3">
          <div className="flex-1 overflow-y-auto scrollbar-hide space-y-0.5">
            {mainMenuItems.map(renderMenuItem)}
          </div>

          <div className="mt-2 pt-2 border-t border-slate-100 space-y-0.5 shrink-0">
            {supportMenuItems.map(renderMenuItem)}
          </div>
        </nav>

        {/* Bottom Actions */}
        <div className="p-4 border-t border-slate-100 space-y-3 shrink-0 bg-slate-50/50">
          {/* Upgrade Card */}
          <div className="bg-gradient-to-br from-indigo-600 to-violet-700 rounded-xl p-4 text-white shadow-lg shadow-indigo-200 relative overflow-hidden group cursor-pointer transition-transform hover:-translate-y-1" onClick={() => handleItemClick('membership')}>
              <div className="absolute top-0 right-0 w-20 h-20 bg-white/10 rounded-full blur-2xl -mr-10 -mt-10 pointer-events-none"></div>

              <div className="flex items-center gap-3 mb-3 relative z-10">
                <div className="p-1.5 bg-white/20 rounded-lg backdrop-blur-sm shadow-inner">
                  <Crown size={16} className="text-yellow-300 fill-yellow-300" />
                </div>
                <div>
                  <h4 className="font-bold text-xs">Nâng cấp Pro</h4>
                  <p className="text-[10px] text-indigo-100 opacity-90">Mở khóa tính năng</p>
                </div>
              </div>

              <div className="w-full py-2 bg-white text-indigo-700 text-xs font-bold rounded-lg shadow-sm flex items-center justify-center gap-2 relative z-10 hover:bg-indigo-50 transition-colors">
                Nâng cấp ngay
              </div>
          </div>

          <button 
            onClick={onLogout}
            className="w-full flex items-center gap-2 px-3 py-2 text-slate-500 hover:text-red-600 hover:bg-red-50 rounded-lg text-sm transition-colors group justify-center"
          >
            <LogOut size={16} className="group-hover:-translate-x-1 transition-transform" />
            Đăng xuất
          </button>
        </div>
      </aside>
    </>
  );
};

export default Sidebar;
